mapper.insert:
update ema_answer
set mood=#{mood},moodlevel=#{moodLevel},
    stresslevel=#{stressLevel},speech_url=#{speechUrl}
    ,pam=#{pam},valence=#{valence},arousal=#{arousal},
    pam_score=#{pamScore},
    img_datas=#{imgDatas},img_selected=#{imgSelected}
where user_id = #{userId} and log_date=#{logDate} and log_time=#{logTime}

mapper.select:
select *
from ema_answer
where user_id=#{userId} and DATEDIFF(NOW(), log_date) < #{period}

select log_date, log_time, mood
from ema_answer
where user_id=#{userId} and log_date=#{date}

select log_date, log_time, pam_score, valence, arousal
from ema_answer
where user_id=#{userId} and log_date=#{date}

select log_date, log_time, pam_score, valence, arousal
from ema_answer
where user_id=#{userId} and DATEDIFF(NOW(), log_date) < #{period}
